import React, { useState, useRef, useEffect } from 'react';
import { PromptDefinition } from '../../types';
import { Loader2, RefreshCw, ChevronRight, Save, Sparkles, Clock, Lightbulb } from 'lucide-react';
import { useToast } from '../../context/ToastContext';

interface FormPanelProps {
  prompt: PromptDefinition;
  formData: Record<string, string>;
  onInputChange: (key: string, value: string) => void;
  onGenerate: () => void;
  isGenerating: boolean;
  onSaveTemplate: () => void;
}

const GET_EXAMPLES = (id: string): Array<Record<string, string>> => {
    const examples: Record<string, Array<Record<string, string>>> = {
        'lesson-planner': [
            { subject: 'Science', grade: '7', topic: 'Photosynthesis', objectives: 'Understand how plants convert light into energy.' },
            { subject: 'Math', grade: '5', topic: 'Fractions', objectives: 'Learn to add and subtract fractions with common denominators.' }
        ],
        'writing-assistant': [
            { doc_type: 'Parent Newsletter', audience: 'Elementary Parents', key_points: 'School picnic update, next week holidays, science fair winners.', tone: 'Warm/Community' },
            { doc_type: 'Grant Proposal', audience: 'Education Foundation', key_points: 'Requesting funds for a new computer lab to improve digital literacy.', tone: 'Professional' }
        ],
        'expert-consultant': [
            { role: 'Child Psychologist', context: 'Students are showing increased anxiety during testing weeks.', question: 'What practical mindfulness exercises can teachers implement?' },
            { role: 'EdTech Specialist', context: 'Transitioning to hybrid learning next semester.', question: 'How can we maintain student engagement in a split environment?' }
        ]
    };
    return examples[id] || [
        { topic: 'Global Warming', audience: 'High School Students', learning_goal: 'Explore impact on coastal cities.' },
        { topic: 'Ancient Rome', audience: 'Grade 6', learning_goal: 'Daily life and governance.' }
    ];
};

const FormPanel: React.FC<FormPanelProps> = ({ 
  prompt, 
  formData, 
  onInputChange, 
  onGenerate, 
  isGenerating,
  onSaveTemplate
}) => {
  const { addToast } = useToast();
  const [panelWidth, setPanelWidth] = useState(400);
  const [isResizing, setIsResizing] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  const startX = useRef(0);
  const startWidth = useRef(0);
  const formDataRef = useRef(formData);

  useEffect(() => {
    formDataRef.current = formData;
  }, [formData]);

  useEffect(() => {
    const key = `autosave_${prompt.id}`;
    const savedData = localStorage.getItem(key);
    if (savedData) {
        try {
            const parsed = JSON.parse(savedData);
            if (parsed && typeof parsed === 'object') {
                Object.entries(parsed).forEach(([k, v]) => {
                    if (typeof v === 'string') onInputChange(k, v);
                });
                addToast("Restored unsaved draft", "info");
                setLastSaved(new Date());
            }
        } catch (e) {}
    }
  }, [prompt.id]);

  useEffect(() => {
    const interval = setInterval(() => {
        const currentData = formDataRef.current;
        if (Object.keys(currentData).length > 0) {
            localStorage.setItem(`autosave_${prompt.id}`, JSON.stringify(currentData));
            setLastSaved(new Date());
        }
    }, 30000);
    return () => clearInterval(interval);
  }, [prompt.id]);

  const handleApplyExample = (example: Record<string, string>) => {
      Object.entries(example).forEach(([k, v]) => onInputChange(k, v));
      addToast("Example applied to form!", "success");
  };

  const startResizing = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsResizing(true);
    startX.current = e.clientX;
    startWidth.current = panelWidth;
  };

  useEffect(() => {
    if (!isResizing) return;
    const handleMouseMove = (e: MouseEvent) => {
      const delta = e.clientX - startX.current;
      setPanelWidth(Math.max(300, Math.min(startWidth.current + delta, 800)));
    };
    const handleMouseUp = () => setIsResizing(false);
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
    return () => {
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isResizing]);

  const promptExamples = GET_EXAMPLES(prompt.id);

  return (
    <div 
      style={{ width: window.innerWidth < 768 ? '100%' : `${panelWidth}px` }}
      className={`bg-white border-r border-slate-200 flex flex-col h-full overflow-hidden relative flex-shrink-0 ${isResizing ? 'select-none' : ''} transition-width duration-200`}
    >
      <div className="p-6 border-b border-slate-100">
        <h2 className="text-xl font-bold text-slate-900">Configure</h2>
        <p className="text-sm text-slate-500 mt-1">{prompt.description}</p>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
        {prompt.fields.map((field) => (
          <div key={field.key} className="space-y-2">
            <label className="text-sm font-semibold text-slate-700 block">{field.label}</label>
            {field.type === 'select' ? (
              <div className="relative">
                <select
                  className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none appearance-none"
                  value={formData[field.key] || ''}
                  onChange={(e) => onInputChange(field.key, e.target.value)}
                >
                  <option value="" disabled>Select option</option>
                  {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
                <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                  <ChevronRight className="rotate-90" size={16} />
                </div>
              </div>
            ) : field.type === 'textarea' ? (
              <textarea
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none min-h-[120px] resize-none"
                placeholder={field.placeholder}
                value={formData[field.key] || ''}
                onChange={(e) => onInputChange(field.key, e.target.value)}
              />
            ) : (
              <input
                type={field.type}
                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none"
                placeholder={field.placeholder}
                value={formData[field.key] || ''}
                onChange={(e) => onInputChange(field.key, e.target.value)}
              />
            )}
          </div>
        ))}

        {/* Example Suggestions */}
        <div className="pt-4 border-t border-slate-100">
            <div className="flex items-center gap-2 mb-3">
                <Lightbulb size={16} className="text-primary" />
                <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider">Example Suggestions</h4>
            </div>
            <div className="flex flex-wrap gap-2">
                {promptExamples.map((ex, idx) => (
                    <button 
                        key={idx}
                        onClick={() => handleApplyExample(ex)}
                        className="text-xs bg-white border border-slate-200 text-slate-600 px-3 py-1.5 rounded-full hover:border-primary hover:text-primary hover:bg-primary/5 transition-all text-left shadow-sm focus:ring-2 focus:ring-primary outline-none"
                    >
                        {ex['topic'] || ex['subject'] || ex['doc_type'] || 'Example Idea'}
                    </button>
                ))}
            </div>
        </div>
      </div>

      <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3">
        {lastSaved && (
             <div className="flex items-center justify-end gap-1.5 text-[10px] text-slate-400 mb-2">
                <Clock size={10} />
                <span>Auto-saved {lastSaved.toLocaleTimeString()}</span>
             </div>
        )}
        <button
          onClick={onGenerate}
          disabled={isGenerating}
          className={`w-full py-4 px-4 rounded-xl flex items-center justify-center gap-3 font-bold text-white transition-all shadow-md hover:shadow-lg relative overflow-hidden transform hover:scale-[1.02] active:scale-95 duration-200
            ${isGenerating ? 'bg-primary cursor-not-allowed' : 'bg-primary hover:bg-amber-400'}`}
        >
          {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <Sparkles size={20} />}
          <span>{isGenerating ? 'Generating...' : 'Generate Content'}</span>
        </button>
        <button onClick={onSaveTemplate} className="w-full py-3 px-4 rounded-xl flex items-center justify-center gap-2 font-medium text-slate-600 border border-slate-200 hover:bg-white hover:border-slate-300 transition-all outline-none focus:ring-2 focus:ring-slate-200">
            <Save size={18} /> Save as Template
        </button>
      </div>

      <div onMouseDown={startResizing} className="hidden md:block absolute top-0 right-0 w-1.5 h-full cursor-col-resize hover:bg-primary/20 z-50 transition-colors" />
    </div>
  );
};

export default FormPanel;

import { GoogleGenAI, Type } from "@google/genai";
import { EvaluationData, NarrativeData, PromptRequestForm, GroundingMetadata } from "../types";

// Initialize the Google GenAI SDK
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Streams content generation for the main document editor.
 */
export const streamContent = async (
  modelName: string,
  systemInstruction: string,
  userPrompt: string,
  onChunk: (text: string) => void,
  onMetadata?: (metadata: GroundingMetadata) => void
) => {
  try {
    const chat = ai.chats.create({
      model: modelName,
      config: {
        systemInstruction: systemInstruction,
        tools: [{googleSearch: {}}],
      },
    });

    const result = await chat.sendMessageStream({ message: userPrompt });

    for await (const chunk of result) {
      if (chunk.text) {
        onChunk(chunk.text);
      }
      if (chunk.candidates?.[0]?.groundingMetadata && onMetadata) {
        onMetadata(chunk.candidates[0].groundingMetadata as GroundingMetadata);
      }
    }
  } catch (error) {
    console.error("Error streaming content:", error);
    throw error;
  }
};

/**
 * Handles follow-up chat messages with optional multi-modal file context.
 */
export const sendChatFollowUp = async (
  modelName: string,
  contextContent: string,
  history: { role: 'user' | 'model', text: string }[],
  newMessage: string,
  customSystemInstruction?: string,
  fileAttachment?: { data: string; mimeType: string }
): Promise<{ text: string, groundingMetadata?: GroundingMetadata }> => {
  try {
    const defaultInstruction = `You are a highly capable AI educational consultant and writing assistant. 

    The user has generated the following educational content: 
    ---
    ${contextContent.substring(0, 25000)}
    ---

    Your goal is to help the user refine, expand, or understand this content.
    If a file is attached, use its content as additional context for your answer.`;

    const instructionToUse = customSystemInstruction 
      ? `${customSystemInstruction}\n\nCONTEXT CONTENT:\n${contextContent.substring(0, 25000)}`
      : defaultInstruction;

    const chat = ai.chats.create({
      model: modelName,
      config: {
        systemInstruction: instructionToUse,
        tools: [{googleSearch: {}}],
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const parts: any[] = [{ text: newMessage }];
    if (fileAttachment) {
      parts.push({
        inlineData: {
          data: fileAttachment.data,
          mimeType: fileAttachment.mimeType
        }
      });
    }

    // Fix: Explicitly define the message as a Content object with parts to resolve type ambiguity
    const result = await chat.sendMessage({ message: { role: 'user', parts } });
    return {
        text: result.text || "I couldn't generate a response.",
        groundingMetadata: result.candidates?.[0]?.groundingMetadata as GroundingMetadata
    };
  } catch (error) {
    console.error("Chat follow-up error:", error);
    throw error;
  }
};

/**
 * Generates an executive summary and a visual illustration for the content.
 */
export const generateNarrativeAssets = async (content: string): Promise<NarrativeData> => {
  // Fix: Upgraded model to gemini-3-flash-preview for basic text summarization tasks
  const summaryResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the following educational content and provide a brief executive summary (max 3 sentences) and 3-5 key takeaways.

    Content:
    ${content.substring(0, 15000)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          keyTakeaways: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "keyTakeaways"]
      }
    }
  });

  const textData = JSON.parse(summaryResponse.text || '{}');

  const imagePrompt = `Create a high-quality, modern, flat-design educational illustration that visually represents this concept: "${textData.summary}". 
  Style: Professional vector art, clean lines, vibrant but professional colors. No text.`;

  let imageUrl = undefined;
  try {
     // Fix: Use the standard Content object structure { parts: [...] } to resolve line 91 'parts' type error
     const imageResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
            parts: [{ text: imagePrompt }]
        },
        config: {
            imageConfig: {
                aspectRatio: "16:9",
            }
        }
     });

     for (const part of imageResponse.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            imageUrl = `data:image/png;base64,${part.inlineData.data}`;
            break;
        }
     }
  } catch (e) {
      console.warn("Image generation failed", e);
  }

  return {
    summary: textData.summary || "No summary available.",
    keyTakeaways: textData.keyTakeaways || [],
    imageUrl
  };
};

/**
 * Evaluates the pedagogical quality of the content.
 */
export const evaluatePedagogy = async (content: string): Promise<EvaluationData> => {
    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Evaluate the following educational content based on pedagogical standards.
        Provide scores from 0 to 100 for Clarity, Relevance, Engagement, and Inclusivity.
        Provide feedback and improvement suggestions.

        Content:
        ${content.substring(0, 15000)}`,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    scores: {
                        type: Type.OBJECT,
                        properties: {
                            clarity: { type: Type.INTEGER },
                            relevance: { type: Type.INTEGER },
                            engagement: { type: Type.INTEGER },
                            inclusivity: { type: Type.INTEGER }
                        }
                    },
                    feedback: { type: Type.STRING },
                    suggestions: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                }
            }
        }
    });

    return JSON.parse(response.text || '{}');
};

/**
 * Architect a valid JSON PromptDefinition from a user request.
 */
export const architectPromptFromRequest = async (request: PromptRequestForm): Promise<string> => {
    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `User Request Data:
        Project Title: ${request.projectTitle}
        Goal: ${request.primaryGoal}
        Task: ${request.specificTask}
        Inputs: ${request.userInputs}
        Output: ${request.outputStructure}
        Tone: ${request.toneStyle}
        Persona: ${request.rolePersona}

        Generate a JSON PromptDefinition for this request.`,
        config: {
            responseMimeType: "application/json"
        }
    });

    return response.text || "{}";
};

import React, { useRef, useEffect, useState } from 'react';
import { ChatMessage, UserProfile, PromptDefinition } from '../../types';
import { Send, User, Sparkles, Loader2, Brain, UserCircle, Link as LinkIcon, Paperclip, X as CloseIcon, FileText as FileIcon } from 'lucide-react';
import { sendChatFollowUp } from '../../services/geminiService';
import { saveChatSession, getChatSession } from '../../services/contentService';
import { useToast } from '../../context/ToastContext';

interface ChatPanelProps {
  prompt: PromptDefinition;
  userEmail: string | undefined;
  user: UserProfile | null;
  contentContext: string;
}

const getDynamicSystemInstruction = (prompt: PromptDefinition) => {
  return `SYSTEM INSTRUCTION & PERSONA DEFINITION:
You are strictly the "${prompt.title}" tool. Your behavior, tone, and logic must align with this specific role.

### YOUR TASK:
Assisting in a follow-up conversation about generated educational content.
If the user uploads a file, use it as grounding context for your answers.
Professional, helpful, and concise.`;
};

const ChatPanel: React.FC<ChatPanelProps> = ({ prompt, userEmail, user, contentContext }) => {
  const { addToast } = useToast();
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [attachedFile, setAttachedFile] = useState<{ name: string; data: string; mimeType: string } | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (userEmail && prompt.id) {
      setIsLoadingHistory(true);
      getChatSession(userEmail, prompt.id)
        .then((msgs) => setMessages(msgs || []))
        .catch(console.error)
        .finally(() => setIsLoadingHistory(false));
    } else {
        setMessages([]);
    }
  }, [userEmail, prompt.id]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isSending]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      addToast("File too large. Max 5MB.", "warning");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const base64Data = (reader.result as string).split(',')[1];
      setAttachedFile({
        name: file.name,
        data: base64Data,
        mimeType: file.type || 'application/octet-stream'
      });
      addToast(`Attached ${file.name}`, "info");
    };
    reader.readAsDataURL(file);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && !attachedFile) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input || (attachedFile ? `[Attached File: ${attachedFile.name}]` : ''),
      timestamp: Date.now()
    };

    const updatedMessages = [...messages, userMessage];
    setMessages(updatedMessages);
    setInput('');
    setIsSending(true);

    const currentFile = attachedFile;
    setAttachedFile(null);

    if (userEmail) saveChatSession(userEmail, prompt.id, updatedMessages);

    try {
      const response = await sendChatFollowUp(
        'gemini-3-flash-preview',
        contentContext,
        updatedMessages.map(m => ({ role: m.role, text: m.text })),
        userMessage.text,
        getDynamicSystemInstruction(prompt),
        currentFile ? { data: currentFile.data, mimeType: currentFile.mimeType } : undefined
      );

      const aiMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.text,
        timestamp: Date.now(),
        groundingMetadata: response.groundingMetadata
      };

      const finalMessages = [...updatedMessages, aiMessage];
      setMessages(finalMessages);

      if (userEmail) saveChatSession(userEmail, prompt.id, finalMessages);

    } catch (error) {
      console.error(error);
      addToast("Failed to get response from AI.", 'error');
    } finally {
      setIsSending(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative" role="region" aria-label={`Chat with AI ${prompt.title}`}>
      {/* Chat History */}
      <div 
        className="flex-1 overflow-y-auto p-4 space-y-8 bg-slate-50"
        aria-live="polite"
        role="log"
      >
        {isLoadingHistory && (
            <div className="flex justify-center p-4">
                <Loader2 className="animate-spin text-slate-400" aria-label="Loading chat history" />
            </div>
        )}

        {!isLoadingHistory && messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center animate-in fade-in duration-500">
            <div className="w-16 h-16 bg-white rounded-full shadow-sm flex items-center justify-center mb-4 border border-slate-100 relative">
              <img src="https://i.postimg.cc/B61fmVMV/IDSS_Logo_D1.png" alt="" className="w-10 h-10 object-contain relative z-10" />
            </div>
            <h3 className="font-medium text-slate-900 mb-1">AI {prompt.title} Assistant</h3>
            <p className="text-sm max-w-xs mx-auto text-slate-500">
               Ask questions about the generated content or upload files for more context.
            </p>
          </div>
        ) : (
          messages.map((msg) => (
            <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className={`flex max-w-[90%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 mt-1 overflow-hidden border bg-white shadow-sm ${msg.role === 'user' ? 'border-blue-200' : 'border-slate-200'}`}>
                  <img src={msg.role === 'user' ? (user?.picture || "https://ui-avatars.com/api/?name=User") : "https://i.postimg.cc/B61fmVMV/IDSS_Logo_D1.png"} alt={msg.role === 'user' ? "You" : "AI"} className="w-full h-full object-cover" />
                </div>

                <div className={`p-4 rounded-2xl shadow-sm text-sm leading-relaxed overflow-hidden flex flex-col ${msg.role === 'user' ? 'bg-white border-2 border-blue-100 text-slate-800 rounded-tr-none' : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'}`}>
                  <div className="max-h-96 overflow-y-auto custom-scrollbar break-words pr-2">
                    <div dangerouslySetInnerHTML={{ __html: msg.text.replace(/\n/g, '<br/>') }} />
                  </div>

                  <div className={`text-[10px] mt-2 pt-2 border-t font-medium ${msg.role === 'user' ? 'text-blue-400 border-blue-50' : 'text-slate-400 border-slate-50'}`}>
                    {msg.role === 'user' ? 'You' : `AI ${prompt.title}`} • {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}

        {isSending && (
          <div className="flex w-full justify-start animate-in fade-in duration-300">
            <div className="flex max-w-[80%] gap-3">
              <div className="w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center flex-shrink-0 mt-1 overflow-hidden">
                <Brain size={18} className="text-primary animate-pulse" />
              </div>
              <div className="bg-white border border-slate-100 p-4 rounded-2xl rounded-tl-none shadow-sm flex flex-col gap-2">
                 <div className="flex items-center gap-2 text-slate-700 font-medium text-sm">
                    <Loader2 size={14} className="animate-spin text-primary" />
                    <span>Thinking...</span>
                 </div>
              </div>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-200 flex-shrink-0 z-10 shadow-sm">
        {attachedFile && (
            <div className="max-w-4xl mx-auto mb-3 flex items-center gap-2 p-2 bg-slate-50 border border-slate-200 rounded-lg animate-in slide-in-from-bottom-2">
                <FileIcon size={16} className="text-primary" />
                <span className="text-xs font-medium text-slate-700 truncate flex-1">{attachedFile.name}</span>
                <button 
                  onClick={() => setAttachedFile(null)} 
                  className="p-1 hover:bg-slate-200 rounded text-slate-500 focus-visible:ring-2 focus-visible:ring-primary outline-none transition-all"
                  aria-label={`Remove file ${attachedFile.name}`}
                >
                    <CloseIcon size={14} />
                </button>
            </div>
        )}

        <form onSubmit={handleSendMessage} className="relative max-w-4xl mx-auto flex items-center gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            onChange={handleFileChange}
            accept=".pdf,.txt,.doc,.docx,image/*"
            aria-hidden="true"
          />
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="p-3 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-200 transition-all shadow-inner focus-visible:ring-2 focus-visible:ring-primary outline-none hover:scale-105 active:scale-95"
            aria-label="Attach context file (PDF, TXT, or Image)"
            title="Attach file"
          >
            <Paperclip size={20} />
          </button>

          <div className="relative flex-1">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={`Ask your ${prompt.title}...`}
              className="w-full pl-4 pr-12 py-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary focus:border-primary transition-all text-sm text-slate-800 placeholder-slate-400 shadow-inner"
              disabled={isSending}
              aria-label="Message text"
            />
            <button 
              type="submit"
              disabled={(!input.trim() && !attachedFile) || isSending}
              className="absolute right-2 top-2.5 p-2 bg-primary text-slate-900 rounded-lg hover:bg-amber-400 disabled:opacity-50 transition-all shadow-sm focus-visible:ring-2 focus-visible:ring-primary outline-none hover:scale-105 active:scale-95"
              aria-label="Send message"
            >
              <Send size={18} />
            </button>
          </div>
        </form>
        <div className="text-center mt-2">
          <span className="text-[10px] text-slate-400" id="chat-hint">AI supports PDF, text and images as additional context.</span>
        </div>
      </div>
    </div>
  );
};

export default ChatPanel;

import React, { useState, useEffect, useRef } from 'react';
import { PromptDefinition, NarrativeData, EvaluationData, UserProfile, ContentType, GroundingMetadata, Collaborator } from '../types';
import { streamContent, generateNarrativeAssets, evaluatePedagogy } from '../services/geminiService';
import { saveGeneratedContent, saveTemplate } from '../services/contentService';
import { CollaborationService } from '../services/collaborationService';
import { useToast } from '../context/ToastContext';
import { Download, FileText, FileCode, MessageSquare, BarChart2, Image as ImageIcon, ChevronDown, FileType, File, Save, Check, X, Printer, Users, Share2, RefreshCw, PenTool } from 'lucide-react';
import { asBlob } from 'html-docx-js-typescript';

import FormPanel from './editor/FormPanel';
import PreviewPanel from './editor/PreviewPanel';
import ChatPanel from './editor/ChatPanel';
import ShareModal from './ShareModal';

declare var html2pdf: any;

interface EditorLayoutProps {
  prompt: PromptDefinition;
  user: UserProfile | null;
  initialFormData?: Record<string, string>;
}

const EditorLayout: React.FC<EditorLayoutProps> = ({ prompt, user, initialFormData }) => {
  const { addToast } = useToast();

  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [content, setContent] = useState('');
  const [narrative, setNarrative] = useState<NarrativeData | null>(null);
  const [evaluation, setEvaluation] = useState<EvaluationData | null>(null);
  const [groundingMetadata, setGroundingMetadata] = useState<GroundingMetadata | null>(null);
  const [activeView, setActiveView] = useState<'document' | 'narrative' | 'analytics' | 'chat'>('document');
  const [loadingExtras, setLoadingExtras] = useState(false);

  const [showExportMenu, setShowExportMenu] = useState(false);
  const [showSaveTemplateModal, setShowSaveTemplateModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [templateName, setTemplateName] = useState('');

  const [collaborators, setCollaborators] = useState<Collaborator[]>([]);
  const [typingCollaborator, setTypingCollaborator] = useState<string | null>(null);
  const [pendingRemoteContent, setPendingRemoteContent] = useState<string | null>(null);

  const collaborationService = useRef<CollaborationService | null>(null);
  const isMounted = useRef(false);
  const currentPromptId = useRef(prompt.id);

  useEffect(() => {
    isMounted.current = true;
    currentPromptId.current = prompt.id;

    const defaults: Record<string, string> = {};
    if (initialFormData) {
        setFormData(initialFormData);
    } else {
        prompt.fields.forEach(f => {
            if (f.defaultValue) defaults[f.key] = f.defaultValue;
        });
        setFormData(defaults);
    }

    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setGroundingMetadata(null);
    setActiveView('document');
    setIsGenerating(false);

    if (user) {
        collaborationService.current = new CollaborationService(prompt.id, user);
        setCollaborators(collaborationService.current.getCollaborators());

        const unsubscribe = collaborationService.current.subscribe((event) => {
             if (event.type === 'presence_update') {
                 setCollaborators(collaborationService.current?.getCollaborators() || []);
             } else if (event.type === 'client_leave') {
                 setCollaborators(collaborationService.current?.getCollaborators() || []);
             } else if (event.type === 'content_update') {
                 if (event.senderId !== user.email) {
                    if (!content) setContent(event.payload.content);
                    else setPendingRemoteContent(event.payload.content);
                 }
             } else if (event.type === 'typing_start') {
                 if (event.senderId !== user.email) {
                    const collab = collaborationService.current?.getCollaborators().find(c => c.userId === event.senderId);
                    if (collab) setTypingCollaborator(`${collab.name} is typing...`);
                 }
             } else if (event.type === 'typing_end') {
                 if (event.senderId !== user.email) setTypingCollaborator(null);
             }
        });

        return () => {
             unsubscribe();
             collaborationService.current?.disconnect();
             collaborationService.current = null;
             isMounted.current = false;
        };
    }
  }, [prompt, initialFormData, user]);

  const handleInputChange = (key: string, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleContentUpdate = (newContent: string) => {
      setContent(newContent);
      collaborationService.current?.sendContentUpdate(newContent);
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    setContent('');
    setActiveView('document');

    let userPrompt = `Task: ${prompt.title}\n`;
    Object.entries(formData).forEach(([key, value]) => {
      const fieldLabel = prompt.fields.find(f => f.key === key)?.label || key;
      userPrompt += `${fieldLabel}: ${value}\n`;
    });

    const masterFormattingInstruction = `Output pure HTML code only. Use inline CSS for a professional enterprise-grade look. Include a clear header, body sections, and a signature block.`;

    try {
      addToast('Generating content...', 'info');
      await streamContent(
        'gemini-3-pro-preview', 
        masterFormattingInstruction, 
        userPrompt,
        (chunk) => {
          if (!isMounted.current) return;
          setContent(prev => prev + chunk);
        },
        (metadata) => {
            if (!isMounted.current) return;
            setGroundingMetadata(metadata);
        }
      );

      if (user) {
        saveGeneratedContent(user.email, {
             type: prompt.title as unknown as ContentType, 
             title: formData['topic'] || prompt.title,
             content: content,
             metadata: formData,
             groundingMetadata: groundingMetadata || undefined
          });
      }
      generateExtras(content);
    } catch (error) {
      addToast("Failed to generate content.", 'error');
    } finally {
      setIsGenerating(false);
    }
  };

  const generateExtras = async (text: string) => {
    setLoadingExtras(true);
    try {
      const [narrativeResult, evaluationResult] = await Promise.all([
        generateNarrativeAssets(text),
        evaluatePedagogy(text)
      ]);
      if (isMounted.current) {
        setNarrative(narrativeResult);
        setEvaluation(evaluationResult);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingExtras(false);
    }
  };

  const handleSaveTemplate = async (e?: React.FormEvent) => {
      if (e) e.preventDefault();
      if (!user || !templateName.trim()) {
          addToast("Template name required", "warning");
          return;
      }
      const id = await saveTemplate(user.email, {
          userId: user.email,
          name: templateName,
          promptId: prompt.id,
          formData: formData
      });
      if (id) {
          addToast("Template saved!", "success");
          setShowSaveTemplateModal(false);
          setTemplateName('');
          window.dispatchEvent(new Event('templateSaved'));
      }
  };

  const handleExport = async (format: 'pdf' | 'docx' | 'txt') => {
      if (!content) return;
      const filename = `${formData['topic'] || 'Document'}_${Date.now()}`;
      try {
        if (format === 'pdf') {
            const element = document.querySelector('.ql-editor') || document.getElementById('document-preview-content');
            if (!element) return;
            html2pdf().set({ margin: 0.5, filename: `${filename}.pdf` }).from(element).save();
        } else if (format === 'docx') {
             const htmlString = `<html><body>${content}</body></html>`;
             const blob = await asBlob(htmlString);
             if (blob) {
                 const url = URL.createObjectURL(blob as Blob);
                 const a = document.createElement('a');
                 a.href = url;
                 a.download = `${filename}.docx`;
                 a.click();
             }
        } else {
            const blob = new Blob([content], { type: 'text/plain' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${filename}.txt`;
            a.click();
        }
      } catch (err) {
        addToast("Export failed.", "error");
      }
      setShowExportMenu(false);
  };

  const getViewButtonClass = (viewName: string) => {
      const isActive = activeView === viewName;
      return `flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all border outline-none focus:ring-2 focus:ring-primary/40 hover:scale-105 active:scale-95
        ${isActive ? 'bg-primary text-slate-900 border-primary shadow-sm' : 'bg-white text-slate-500 border-transparent hover:bg-slate-50'}`;
  };

  return (
    <div className="flex h-full overflow-hidden relative flex-col md:flex-row">
      <ShareModal isOpen={showShareModal} onClose={() => setShowShareModal(false)} title={prompt.title} user={user} />

      {showSaveTemplateModal && (
          <div className="absolute inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in duration-200">
              <div className="bg-white rounded-xl shadow-2xl w-full max-w-md animate-in zoom-in-95 duration-200">
