import React, { useEffect, useRef } from 'react';
import { NarrativeData, EvaluationData, PromptDefinition, GroundingMetadata } from '../../types';
import { Loader2, FileText, Image as ImageIcon, Link as LinkIcon, Undo2, Redo2 } from 'lucide-react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar } from 'recharts';

declare global {
    interface Window {
        Quill: any;
    }
}

interface PreviewPanelProps {
  activeView: 'document' | 'narrative' | 'analytics' | 'chat';
  content: string;
  narrative: NarrativeData | null;
  evaluation: EvaluationData | null;
  groundingMetadata: GroundingMetadata | null;
  loadingExtras: boolean;
  isGenerating: boolean;
  prompt: PromptDefinition;
  formData: Record<string, string>;
  onContentUpdate?: (newContent: string) => void;
}

const PreviewPanel: React.FC<PreviewPanelProps> = ({
  activeView,
  content,
  narrative,
  evaluation,
  groundingMetadata,
  loadingExtras,
  isGenerating,
  prompt,
  formData,
  onContentUpdate
}) => {
  const quillRef = useRef<any>(null);
  const editorContainerRef = useRef<HTMLDivElement>(null);
  const isQuillInitialized = useRef(false);

  useEffect(() => {
    if (activeView === 'document' && !isGenerating && editorContainerRef.current) {
        if (!isQuillInitialized.current && window.Quill) {
            const icons = window.Quill.import('ui/icons');
            // Custom Icons using strings as per Quill requirements
            icons['undo'] = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round"><path d="M3 7v6h6"></path><path d="M21 17a9 9 0 0 0-9-9 9 9 0 0 0-6 2.3L3 13"></path></svg>';
            icons['redo'] = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round"><path d="M21 7v6h-6"></path><path d="M3 17a9 9 0 0 1 9-9 9 9 0 0 1 6 2.3l3 2.7"></path></svg>';

            quillRef.current = new window.Quill(editorContainerRef.current, {
                theme: 'snow',
                modules: {
                    history: { delay: 2000, maxStack: 500, userOnly: true },
                    toolbar: {
                        container: [
                            [{ 'header': [1, 2, 3, false] }],
                            ['bold', 'italic', 'underline'],
                            [{ 'list': 'ordered'}, { 'list': 'bullet' }],
                            [{ 'align': [] }],
                            ['clean'],
                            ['undo', 'redo']
                        ],
                        handlers: {
                            'undo': function() { this.quill.history.undo(); },
                            'redo': function() { this.quill.history.redo(); }
                        }
                    }
                }
            });

            if (content) quillRef.current.clipboard.dangerouslyPasteHTML(content);

            quillRef.current.on('text-change', () => {
                 if (onContentUpdate && quillRef.current) {
                     onContentUpdate(quillRef.current.root.innerHTML);
                 }
            });

            isQuillInitialized.current = true;
        }
    }

    return () => {
        if (activeView !== 'document' || isGenerating) {
             isQuillInitialized.current = false;
             quillRef.current = null;
        }
    };
  }, [activeView, isGenerating]);

  if (!content && !isGenerating) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-slate-400">
         <FileText size={48} className="opacity-20 mb-4" />
         <p className="text-sm font-medium">Generate content to view document editor.</p>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex flex-col relative bg-slate-100 overflow-hidden">
      {isGenerating && !content && (
         <div className="absolute inset-0 z-50 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center animate-in fade-in duration-300">
             <Loader2 size={40} className="text-primary animate-spin mb-4" />
             <h3 className="text-lg font-bold text-slate-800">Drafting your {prompt.title}...</h3>
         </div>
      )}

      {activeView === 'document' && (
        <div className="w-full h-full flex flex-col overflow-hidden">
            <style>
            {`
                .ql-editor { padding: 40px !important; max-width: 900px; margin: 0 auto; background: white; min-height: 100%; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
                .ql-toolbar.ql-snow { border: none !important; border-bottom: 1px solid #e2e8f0 !important; background: #f8fafc; sticky top: 0; z-index: 10; }
                .ql-container.ql-snow { border: none !important; flex: 1; overflow-y: auto; background: #f1f5f9; }
                .ql-formats { margin-right: 15px !important; }
            `}
            </style>
            {isGenerating ? (
                <div className="flex-1 p-10 overflow-y-auto bg-white prose max-w-none">
                    <div dangerouslySetInnerHTML={{ __html: content.replace(/\n/g, '<br/>') }} />
                </div>
            ) : (
                <div ref={editorContainerRef} className="flex-1 flex flex-col"></div>
            )}
        </div>
      )}

      {activeView === 'narrative' && (
        <div className="p-8 max-w-4xl mx-auto w-full space-y-6 overflow-y-auto">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="text-lg font-bold mb-4">Executive Summary</h3>
                <p className="text-slate-700 leading-relaxed">{narrative?.summary || 'Generating summary...'}</p>
            </div>
            {narrative?.imageUrl && (
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <img src={narrative.imageUrl} alt="Summary" className="w-full rounded-lg shadow-inner" />
                </div>
            )}
        </div>
      )}

      {activeView === 'analytics' && (
        <div className="p-8 max-w-4xl mx-auto w-full space-y-6 overflow-y-auto">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-80">
                    <h3 className="text-lg font-bold mb-4">Quality Metrics</h3>
                    {evaluation ? (
                        <ResponsiveContainer width="100%" height="100%">
                            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={[
                                { subject: 'Clarity', A: evaluation.scores.clarity },
                                { subject: 'Relevance', A: evaluation.scores.relevance },
                                { subject: 'Engagement', A: evaluation.scores.engagement },
                                { subject: 'Inclusivity', A: evaluation.scores.inclusivity },
                            ]}>
                                <PolarGrid />
                                <PolarAngleAxis dataKey="subject" />
                                <Radar name="Score" dataKey="A" stroke="#035EA1" fill="#035EA1" fillOpacity={0.4} />
                            </RadarChart>
                        </ResponsiveContainer>
                    ) : <Loader2 className="animate-spin mx-auto mt-10" />}
                </div>
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-lg font-bold mb-4">Improvement Suggestions</h3>
                    <ul className="space-y-2">
                        {evaluation?.suggestions.map((s, i) => <li key={i} className="text-sm p-3 bg-blue-50 text-blue-800 rounded-lg border border-blue-100">💡 {s}</li>)}
                    </ul>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

